('pleural', 'hero',            'title',         'Page Title',          'Pleural Effusion Analysis',                                                                                                                                                                                                    'text'),
('pleural', 'hero',            'subtitle',      'Page Subtitle',       'Comprehensive body fluid cytology for accurate diagnosis',                                                                                                                                                                     'text'),
('pleural', 'overview',        'badge',         'Section Badge',       'Body Fluid Analysis',                                                                                                                                                                                                          'text'),
('pleural', 'overview',        'body',          'Section Body',        'Awalife helps standardize pleural and abdominal effusion review by combining high-quality microscopy imaging with AI-assisted morphology recognition. Results are delivered as a review-ready report with images and structured findings, including up to 19 reportable items.', 'text'),
('pleural', 'overview',        'cta_primary',   'Primary CTA',         'Contact us',                                                                                                                                                                                                                   'text'),
('pleural', 'classification',  'badge',         'Section Badge',       'Cell Counting',                                                                                                                                                                                                                'text'),
('pleural', 'classification',  'subtitle',      'Section Body',        'In many workflows, TNCC is approximated using total WBC counts, which can overlook non-WBC formed elements and introduce variability across operators and methods. Awalife takes a morphology-first approach: it captures true-to-life microscopy images and performs morphology-based TNCC enumeration, counting nucleated cells based on what is actually present in the sample. The result is a review-ready output with image evidence, supporting more consistent TNCC reporting and clearer clinical communication for pleural and abdominal effusions.', 'text'),
('pleural', 'clinical_images', 'badge',         'Section Badge',       'Image Quality',                                                                                                                                                                                                                'text'),
('pleural', 'clinical_images', 'subtitle',      'Section Subtitle',    'Review your report and verify the images with confidence - and tap into Awalife''s clinical specialists whenever needed.',                                                                                                     'text'),
('pleural', 'cta',             'title',         'CTA Title',           'Interested in Our Products?',                                                                                                                                                                                                  'text'),
('pleural', 'cta',             'body',          'CTA Body',            'Contact our team for pricing, demonstrations, and technical specifications tailored to your clinic''s needs.',                                                                                                                 'text'),

